struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: convert to little-endian and write
        adaptor.write(hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(sensor_id));

        for (const auto& temp : temperatures) {
            float converted = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(temp);
            adaptor.write(converted);
        }

        double converted_pressure = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(pressure);
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization: read and convert from little-endian to native
        sensor_id = adaptor.read<uint32_t>();

        for (auto& temp : temperatures) {
            float read_temp = adaptor.read<float>();
            hexi::endian::little_to_native_inplace(read_temp);
            temp = read_temp;
        }

        double read_pressure = adaptor.read<double>();
        hexi::endian::little_to_native_inplace(read_pressure);
        pressure = read_pressure;
    }
};

